@namespace Lumeo

<div class="@CssClass" role="group" aria-label="@AriaLabel" @attributes="AdditionalAttributes">
    @ChildContent
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter] public Lumeo.Orientation Orientation { get; set; } = Lumeo.Orientation.Horizontal;
    /// <summary>
    /// Accessible name for the button group (exposes it to AT as a named
    /// <c>role="group"</c>). Roving tabindex is intentionally NOT forced here —
    /// a ButtonGroup commonly wraps independent actions that each need their own
    /// tab stop; use <c>Toolbar</c> for single-tab-stop/arrow-key navigation. (#270)
    /// </summary>
    [Parameter] public string? AriaLabel { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge(
        Orientation == Lumeo.Orientation.Horizontal ? HorizontalClasses : VerticalClasses,
        Class);

    // Horizontal: first button gets left-rounded, last gets right-rounded, middle ones square.
    // -ml-px collapses the shared border between adjacent buttons.
    private const string HorizontalClasses =
        "inline-flex flex-row " +
        "[&>button:not(:first-child)]:rounded-l-none " +
        "[&>button:not(:last-child)]:rounded-r-none " +
        "[&>button:not(:first-child)]:-ml-px " +
        "[&>button:not(:first-child)]:border-l-border/40";

    // Vertical: first button gets top-rounded, last gets bottom-rounded, middle ones square.
    // -mt-px collapses the shared border between adjacent buttons.
    private const string VerticalClasses =
        "inline-flex flex-col " +
        "[&>button:not(:first-child)]:rounded-t-none " +
        "[&>button:not(:last-child)]:rounded-b-none " +
        "[&>button:not(:first-child)]:-mt-px " +
        "[&>button:not(:first-child)]:border-t-border/40";

}
